//! Rendering helpers shared across every per-target emitter.
//!
//! These routines are purely presentation-layer: string literal escaping,
//! case conversion, param-type projection per language, and the shared
//! `@generated` header. Nothing here mutates the spec.

use std::fmt::Write as _;

use super::spec::{ParamSpec, ParamType, UtilitySpec};

pub(super) fn generated_header() -> &'static str {
    "// @generated DO NOT EDIT — regenerated by build.rs from sdk_surface.toml\n\n"
}

